const body = $input.first().json.body || $input.first().json;
const { file_data, mime_type, filename } = body;

if (!file_data) {
  throw new Error('No file_data provided');
}

const buffer = Buffer.from(file_data, 'base64');
const binary = await this.helpers.prepareBinaryData(
  buffer,
  filename || 'license-disk.jpg',
  mime_type || 'image/jpeg'
);

return {
  json: { filename, mime_type, sizeBytes: buffer.length },
  binary: { data: binary }
};

const response = items[0].json;

// With simplifyOutput, Gemini may return the text directly or nested
let text = '';
if (typeof response === 'string') {
  text = response;
} else if (typeof response.text === 'string') {
  text = response.text;
} else if (typeof response.output === 'string') {
  text = response.output;
} else if (typeof response.content === 'string') {
  text = response.content;
} else if (response.content && response.content.parts && response.content.parts.length > 0) {
  text = String(response.content.parts[0].text || '');
} else if (response.candidates && response.candidates.length > 0) {
  const parts = response.candidates[0].content.parts;
  if (parts && parts.length > 0) text = String(parts[0].text || '');
} else {
  // Maybe the response IS the parsed object already
  if (response.registration || response.make || response.vin) {
    return [{ json: {
      registration: response.registration || '',
      eNatisRegNumber: response.eNatisRegNumber || '',
      make: response.make || '',
      model: response.model || '',
      bodyType: response.bodyType || '',
      year: response.year || null,
      vin: response.vin || '',
      engineNumber: response.engineNumber || '',
      color: response.color || '',
      tareMass: response.tareMass || null,
      expiryDate: response.expiryDate || null,
      firstRegistrationDate: response.firstRegistrationDate || null,
      ownerName: response.ownerName || '',
      confidence: response.confidence || 'medium'
    } }];
  }
  text = JSON.stringify(response);
}

if (!text) {
  return [{ json: { error: 'AI could not read the license disk. Please try a clearer photo.' } }];
}

let jsonStr = text.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

const firstBrace = jsonStr.indexOf('{');
if (firstBrace > 0) jsonStr = jsonStr.substring(firstBrace);
if (!jsonStr.endsWith('}')) {
  const lastBrace = jsonStr.lastIndexOf('}');
  if (lastBrace > 0) jsonStr = jsonStr.substring(0, lastBrace + 1);
}

try {
  const parsed = JSON.parse(jsonStr);
  return [{ json: {
    registration: parsed.registration || '',
    vehicleRegNumber: parsed.vehicleRegNumber || '',
    eNatisNumber: parsed.eNatisNumber || '',
    make: parsed.make || '',
    model: parsed.model || '',
    bodyType: parsed.bodyType || '',
    year: parsed.year || null,
    vin: parsed.vin || '',
    engineNumber: parsed.engineNumber || '',
    color: parsed.color || '',
    tareMass: parsed.tareMass || null,
    gvm: parsed.gvm || null,
    seatingCapacity: parsed.seatingCapacity || null,
    expiryDate: parsed.expiryDate || null,
    firstRegistrationDate: parsed.firstRegistrationDate || null,
    confidence: parsed.confidence || 'medium'
  } }];
} catch (e) {
  return [{ json: { error: 'AI response was not valid JSON. Please try again with a clearer photo.', raw: String(text) } }];
}
